import React, { useState } from 'react';

const App = () => {
  const [credits, setCredits] = useState(100);
  const [incrementValue, setIncrementValue] = useState(-10);

  const handleIncrement = () => {
    setCredits((prevCredits) => prevCredits + incrementValue);
  };

  const handleDecrement = () => {
    if (credits > 0) {
      setCredits((prevCredits) => prevCredits - incrementValue);
    }
  };

  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <div className="bg-white p-4 w-[300px]">
        <h2 className="text-2xl font-bold mb-4">AI Model Credit Tracker</h2>
        <p className="text-lg font-bold mb-4">Current Credits:</p>
        <p className="text-2xl font-bold mb-4">{credits}</p>
        <div className="flex justify-between mt-4">
          <button className="bg-[#C06C88] text-white px-4 py-2 rounded-lg" onClick={handleIncrement}>-</button>
          <button className="bg-[#C06C88] text-white px-4 py-2 rounded-lg" onClick={handleDecrement}>+</button>
        </div>
      </div>
    </div>
  );
};

export default App;
